// ============================================================
// PARSE & VALIDATE INCIDENT ARTIFACTS
// ============================================================
// Normalize the incoming webhook payload into the AlertPayload
// format expected by the agent's /api/v1/enrich endpoint.
// Handles both the demo scenario.json format and the generic
// SIEM alert format.
// ============================================================

const raw = $input.first().json.body || $input.first().json;

// Detect format: full scenario vs. generic alert
const isScenarioFormat = !!raw.artifacts;
let payload = {};

if (isScenarioFormat) {
  // Full scenario format (like demo/scenario.json)
  const a = raw.artifacts;
  const v = raw.victim || {};

  // Extract hashes
  const hashes = [];
  if (a.hashes) {
    for (const [key, val] of Object.entries(a.hashes)) {
      const hashVal = String(val);
      // Strip prefix like "sha256:"
      const clean = hashVal.includes(':') ? hashVal.split(':')[1] : hashVal;
      hashes.push(clean);
    }
  }

  // Extract IPs and domains
  const ips = [];
  const domains = [];
  if (a.network_iocs) {
    for (const ioc of a.network_iocs) {
      if (ioc.type === 'ip') ips.push(ioc.value);
      else if (ioc.type === 'domain') domains.push(ioc.value);
    }
  }

  // Extract observed TTPs from persistence, lateral movement, and LOLBAS
  const observedTtps = [];
  if (a.persistence) {
    for (const p of a.persistence) {
      observedTtps.push(`${p.type}: ${p.name || p.command || ''}`);
    }
  }
  if (a.lateral_movement) {
    for (const lm of a.lateral_movement) {
      observedTtps.push(`${lm.method} lateral movement from ${lm.source} to ${lm.destination}`);
    }
  }
  if (a.lolbas) {
    observedTtps.push(...a.lolbas);
  }

  payload = {
    alert_id: raw.incident_id || `IR-${Date.now()}`,
    source: 'n8n-ir-pipeline',
    severity: 'critical',
    description: `Ransomware incident at ${v.company || 'Unknown'}`,
    hostname: '',
    victim_company: v.company || '',
    victim_sector: v.sector || '',
    hashes: hashes,
    ips: ips,
    domains: domains,
    ransom_note_text: a.ransom_note?.content || '',
    file_extension: a.file_extension || '',
    observed_ttps: observedTtps
  };
} else {
  // Generic alert format (AlertPayload)
  payload = {
    alert_id: raw.alert_id || `IR-${Date.now()}`,
    source: raw.source || 'n8n-ir-pipeline',
    severity: raw.severity || 'high',
    description: raw.description || '',
    hostname: raw.hostname || '',
    victim_company: raw.victim_company || '',
    victim_sector: raw.victim_sector || '',
    hashes: raw.hashes || [],
    ips: raw.ips || [],
    domains: raw.domains || [],
    ransom_note_text: raw.ransom_note_text || '',
    file_extension: raw.file_extension || '',
    observed_ttps: raw.observed_ttps || []
  };
}

// Validation
const hasData = payload.hashes.length > 0 || 
                payload.ips.length > 0 || 
                payload.ransom_note_text.length > 0 ||
                payload.observed_ttps.length > 0;

return [{
  json: {
    alert_payload: payload,
    incident_id: payload.alert_id,
    victim_company: payload.victim_company,
    victim_sector: payload.victim_sector,
    has_data: hasData,
    artifact_summary: {
      hashes: payload.hashes.length,
      ips: payload.ips.length,
      domains: payload.domains.length,
      has_ransom_note: payload.ransom_note_text.length > 0,
      observed_ttps: payload.observed_ttps.length,
      file_extension: payload.file_extension
    }
  }
}];

// ============================================================
// FALLBACK: LOCAL ATTRIBUTION
// ============================================================
// If the agent endpoint is unavailable, perform basic
// attribution using direct ransomware.live API calls.
// This mirrors the graceful degradation philosophy.
// ============================================================

const OBSERVATION_TO_MITRE = {
  'rdp': ['T1021.001'], 'psexec': ['T1021.002', 'T1569.002'],
  'wmi': ['T1047'], 'wmic': ['T1047'], 'schtasks': ['T1053.005'],
  'scheduled task': ['T1053.005'], 'registry run key': ['T1547.001'],
  'rclone': ['T1567.002'], 'vssadmin': ['T1490'],
  'bcdedit': ['T1490'], 'cobalt strike': ['T1059.001', 'T1071.001'],
  'powershell': ['T1059.001'], 'certutil': ['T1140', 'T1105'],
  'ransomware': ['T1486'], 'encryption': ['T1486'],
  'data exfiltration': ['T1041', 'T1567']
};

const payload = $('Parse Incident Artifacts').first().json.alert_payload;
const callResult = $input.first().json;

// Check if agent call succeeded
const agentSuccess = callResult.primary_group && 
                     callResult.primary_group !== '' &&
                     !callResult.error;

if (agentSuccess) {
  // Agent returned valid results
  return [{
    json: {
      source: 'agent',
      incident_id: callResult.incident_id || payload.alert_id,
      primary_group: callResult.primary_group,
      confidence_pct: callResult.confidence_pct || 0,
      confidence_label: callResult.confidence_label || 'Unknown',
      brief: callResult.brief || '',
      ioc_matches: callResult.ioc_matches || [],
      mitre_techniques: callResult.mitre_techniques || [],
      errors: callResult.errors || [],
      victim_company: payload.victim_company,
      victim_sector: payload.victim_sector,
      alert_payload: payload
    }
  }];
}

// Fallback: basic MITRE mapping from observed TTPs
const mitreIds = new Set();
for (const obs of (payload.observed_ttps || [])) {
  const lower = obs.toLowerCase();
  for (const [keyword, techniques] of Object.entries(OBSERVATION_TO_MITRE)) {
    if (lower.includes(keyword)) {
      techniques.forEach(t => mitreIds.add(t));
    }
  }
}

return [{
  json: {
    source: 'fallback',
    incident_id: payload.alert_id,
    primary_group: 'Unknown (agent unavailable)',
    confidence_pct: 0,
    confidence_label: 'Insufficient',
    brief: 'Agent endpoint unavailable. Performing basic analysis with direct API calls.',
    ioc_matches: [],
    mitre_techniques: Array.from(mitreIds).sort(),
    errors: ['Agent endpoint unavailable or returned error. Using fallback analysis.'],
    victim_company: payload.victim_company,
    victim_sector: payload.victim_sector,
    alert_payload: payload
  }
}];

// ============================================================
// MERGE & BUILD EXECUTIVE SUMMARY
// ============================================================
// Combine attribution results with all parallel enrichment
// data into a comprehensive executive summary.
// ============================================================

const items = $input.all();

// Collect data from all upstream nodes
let attribution = null;
let groupProfile = null;
let yaraRules = [];
let sectorVictims = [];
let secFilings = [];

// Walk through all inputs and classify them
for (const item of items) {
  const d = item.json;

  if (d.primary_group || d.incident_id) {
    // Attribution data from Parse Attribution
    if (d.confidence_pct !== undefined) attribution = d;
  }
  if (d.name && d.description && !d.primary_group) {
    groupProfile = d;
  }
  if (d.yara || d.rule || (Array.isArray(d) && d[0]?.rule)) {
    yaraRules = Array.isArray(d) ? d : [d];
  }
}

// Use the attribution from the Parse Attribution node directly
if (!attribution) {
  try {
    attribution = $('Parse Attribution / Fallback').first().json;
  } catch(e) {
    attribution = {
      incident_id: 'UNKNOWN',
      primary_group: 'Unknown',
      confidence_pct: 0,
      confidence_label: 'Insufficient',
      brief: '',
      mitre_techniques: [],
      errors: ['Could not retrieve attribution data']
    };
  }
}

// Try to get group profile
if (!groupProfile) {
  try {
    groupProfile = $('Fetch Group Profile').first().json;
  } catch(e) {
    groupProfile = { name: attribution.primary_group, description: 'Profile unavailable' };
  }
}

// Try to get YARA
try {
  const yaraData = $('Fetch YARA Rules').first().json;
  yaraRules = Array.isArray(yaraData) ? yaraData : [yaraData];
} catch(e) { /* no YARA available */ }

// Try to get sector victims
try {
  const sv = $('Fetch Sector Victims').first().json;
  sectorVictims = Array.isArray(sv) ? sv.slice(0, 10) : [];
} catch(e) { /* no sector data */ }

// Try to get SEC filings
try {
  const sf = $('Check SEC 8-K Filings').first().json;
  secFilings = Array.isArray(sf) ? sf.slice(0, 5) : [];
} catch(e) { /* no filings data */ }

const now = new Date().toISOString();
const group = attribution.primary_group || 'Unknown';
const confidence = attribution.confidence_pct || 0;
const label = attribution.confidence_label || 'Insufficient';

// Count sector victims from the attributed group
const groupSectorVictims = sectorVictims.filter(v => 
  (v.group_name || v.group || '').toLowerCase() === group.toLowerCase()
);

return [{
  json: {
    incident_id: attribution.incident_id,
    primary_group: group,
    confidence_pct: confidence,
    confidence_label: label,
    source: attribution.source || 'agent',
    agent_brief: attribution.brief || '',
    mitre_techniques: attribution.mitre_techniques || [],
    ioc_matches: attribution.ioc_matches || [],
    errors: attribution.errors || [],
    group_profile: {
      name: groupProfile.name || group,
      description: (groupProfile.description || '').substring(0, 500),
      locations: groupProfile.locations || 'Unknown',
      first_seen: groupProfile.first_seen || 'Unknown'
    },
    yara_rules_count: yaraRules.filter(r => r && r.rule).length,
    yara_rules: yaraRules,
    sector_context: {
      sector: attribution.victim_sector || 'Unknown',
      total_sector_victims: sectorVictims.length,
      group_sector_victims: groupSectorVictims.length
    },
    sec_filings_count: secFilings.length,
    sec_filings: secFilings,
    victim_company: attribution.victim_company || '',
    victim_sector: attribution.victim_sector || '',
    generated_at: now
  }
}];

// ============================================================
// GENERATE FULL IR BRIEF (Markdown)
// ============================================================
// Render a comprehensive Incident Response brief matching
// the structure of templates/ir_brief.md.j2 from the agent.
// ============================================================

const d = $input.first().json;
const now = d.generated_at;

let md = '';

// Header
md += `# Incident Response Intelligence Brief\n\n`;
md += `| Field | Value |\n|-------|-------|\n`;
md += `| **Incident ID** | ${d.incident_id} |\n`;
md += `| **Primary Attribution** | ${d.primary_group} |\n`;
md += `| **Confidence** | ${d.confidence_pct}% (${d.confidence_label}) |\n`;
md += `| **Victim** | ${d.victim_company} |\n`;
md += `| **Sector** | ${d.victim_sector} |\n`;
md += `| **Generated** | ${now} |\n`;
md += `| **Source** | ${d.source === 'agent' ? 'AI Agent Attribution' : 'Fallback Analysis'} |\n\n`;

// Executive Summary
md += `---\n\n## Executive Summary\n\n`;
if (d.agent_brief) {
  md += `${d.agent_brief}\n\n`;
} else {
  md += `An incident at **${d.victim_company}** (${d.victim_sector} sector) has been `;
  md += `attributed to **${d.primary_group}** with **${d.confidence_label}** confidence `;
  md += `(${d.confidence_pct}%).\n\n`;
}

// Threat Actor Profile
md += `---\n\n## Threat Actor: ${d.group_profile.name}\n\n`;
if (d.group_profile.description) {
  md += `${d.group_profile.description}\n\n`;
}
md += `- **Suspected Location:** ${d.group_profile.locations}\n`;
md += `- **Active Since:** ${d.group_profile.first_seen}\n\n`;

// MITRE ATT&CK
if (d.mitre_techniques && d.mitre_techniques.length > 0) {
  md += `---\n\n## MITRE ATT&CK Techniques\n\n`;
  md += `| Technique ID | Link |\n|-------------|------|\n`;
  for (const t of d.mitre_techniques) {
    const id = typeof t === 'string' ? t : t.technique_id;
    md += `| ${id} | [View](https://attack.mitre.org/techniques/${id.replace('.', '/')}) |\n`;
  }
  md += `\n`;
}

// IOC Matches
if (d.ioc_matches && d.ioc_matches.length > 0) {
  md += `---\n\n## IOC Matches\n\n`;
  md += `${d.ioc_matches.length} indicators matched against known ransomware infrastructure.\n\n`;
}

// YARA Rules
if (d.yara_rules_count > 0) {
  md += `---\n\n## YARA Rules\n\n`;
  md += `**${d.yara_rules_count} detection rules** available for ${d.primary_group}.\n`;
  md += `Deploy these across all endpoints for a detection sweep.\n\n`;
}

// Sector Context
md += `---\n\n## Sector Threat Context\n\n`;
md += `- **Sector:** ${d.sector_context.sector}\n`;
md += `- **Total Recent Sector Victims:** ${d.sector_context.total_sector_victims}\n`;
md += `- **Victims by ${d.primary_group}:** ${d.sector_context.group_sector_victims}\n\n`;

// SEC Filings
if (d.sec_filings_count > 0) {
  md += `---\n\n## SEC 8-K Cybersecurity Disclosures\n\n`;
  md += `${d.sec_filings_count} relevant SEC filings found.\n\n`;
}

// Recommended Actions
md += `---\n\n## Recommended Immediate Actions\n\n`;
md += `1. **Isolate affected systems** — Disconnect compromised hosts from the network\n`;
md += `2. **Preserve evidence** — Image affected systems before remediation\n`;
md += `3. **Reset credentials** — All domain admin and service accounts\n`;
md += `4. **Deploy YARA rules** — Sweep all endpoints for ${d.primary_group} indicators\n`;
md += `5. **Block IOCs** — Add all matched IPs, domains, and hashes to blocklists\n`;
md += `6. **Engage legal counsel** — Assess notification obligations\n`;
md += `7. **Contact insurance** — Initiate cyber insurance claim process\n`;
md += `8. **Monitor for re-entry** — ${d.primary_group} is known to maintain persistence\n\n`;

// Errors/Warnings
if (d.errors && d.errors.length > 0) {
  md += `---\n\n## Processing Notes\n\n`;
  for (const err of d.errors) {
    md += `- ${err}\n`;
  }
  md += `\n`;
}

md += `---\n\n_Generated by n8n IR Pipeline + AI-Powered Ransomware Intelligence Agent_\n`;
md += `_SANS Webinar Demo — Stay Ahead of Ransomware_`;

return [{
  json: {
    ...d,
    ir_brief_markdown: md
  }
}];

// HIGH CONFIDENCE PATH — Immediate Escalation
const d = $input.first().json;

return [{
  json: {
    ...d,
    escalation_level: 'CRITICAL',
    escalation_action: 'immediate',
    sla_hours: 1,
    notifications: ['slack_critical', 'email_ir_team', 'siem_webhook'],
    slack_message: `:rotating_light: *CRITICAL: Ransomware Incident — ${d.confidence_label} Confidence*\n\n` +
      `*Incident:* ${d.incident_id}\n` +
      `*Victim:* ${d.victim_company} (${d.victim_sector})\n` +
      `*Attribution:* *${d.primary_group}* at *${d.confidence_pct}%* confidence\n\n` +
      `*Immediate Actions Required:*\n` +
      `1. Isolate affected systems\n` +
      `2. Preserve forensic evidence\n` +
      `3. Reset domain admin credentials\n` +
      `4. Deploy YARA rules (${d.yara_rules_count} available)\n\n` +
      `Full IR brief has been emailed to the incident response team.\n` +
      `MITRE Techniques: ${(d.mitre_techniques || []).slice(0, 5).join(', ')}\n\n` +
      `@here — Please acknowledge in thread.`
  }
}];

// MEDIUM CONFIDENCE PATH — Queue for SOC Review
const d = $input.first().json;

return [{
  json: {
    ...d,
    escalation_level: 'HIGH',
    escalation_action: 'queue_review',
    sla_hours: 4,
    notifications: ['slack_soc', 'siem_webhook'],
    slack_message: `:warning: *Ransomware Intelligence: Medium Confidence Attribution*\n\n` +
      `*Incident:* ${d.incident_id}\n` +
      `*Victim:* ${d.victim_company} (${d.victim_sector})\n` +
      `*Attribution:* ${d.primary_group} at ${d.confidence_pct}% confidence\n\n` +
      `Additional analyst review recommended. Full brief available.\n` +
      `SLA: 4 hours`
  }
}];

// LOW CONFIDENCE PATH — Log Only
const d = $input.first().json;

return [{
  json: {
    ...d,
    escalation_level: 'MEDIUM',
    escalation_action: 'log',
    sla_hours: 24,
    notifications: ['siem_webhook'],
    slack_message: `:information_source: *Low Confidence Attribution Logged*\n\n` +
      `*Incident:* ${d.incident_id} — ${d.primary_group} at ${d.confidence_pct}%\n` +
      `Logged for tracking. No immediate action required.`
  }
}];

// Build final response combining escalation + full data
const d = $input.first().json;

return [{
  json: {
    status: 'complete',
    incident_id: d.incident_id,
    primary_group: d.primary_group,
    confidence_pct: d.confidence_pct,
    confidence_label: d.confidence_label,
    escalation_level: d.escalation_level,
    escalation_action: d.escalation_action,
    sla_hours: d.sla_hours,
    notifications_sent: d.notifications,
    summary: {
      mitre_techniques_count: (d.mitre_techniques || []).length,
      ioc_matches_count: (d.ioc_matches || []).length,
      yara_rules_count: d.yara_rules_count || 0,
      sec_filings_count: d.sec_filings_count || 0
    },
    group_profile: d.group_profile,
    mitre_techniques: d.mitre_techniques,
    ir_brief_markdown: d.ir_brief_markdown,
    generated_at: d.generated_at
  }
}];

// Build final response for medium path
const d = $input.first().json;

return [{
  json: {
    status: 'complete',
    incident_id: d.incident_id,
    primary_group: d.primary_group,
    confidence_pct: d.confidence_pct,
    confidence_label: d.confidence_label,
    escalation_level: d.escalation_level,
    escalation_action: d.escalation_action,
    sla_hours: d.sla_hours,
    notifications_sent: d.notifications,
    summary: {
      mitre_techniques_count: (d.mitre_techniques || []).length,
      ioc_matches_count: (d.ioc_matches || []).length,
      yara_rules_count: d.yara_rules_count || 0,
      sec_filings_count: d.sec_filings_count || 0
    },
    group_profile: d.group_profile,
    mitre_techniques: d.mitre_techniques,
    ir_brief_markdown: d.ir_brief_markdown,
    generated_at: d.generated_at
  }
}];

// Build final response for low path
const d = $input.first().json;

return [{
  json: {
    status: 'complete',
    incident_id: d.incident_id,
    primary_group: d.primary_group,
    confidence_pct: d.confidence_pct,
    confidence_label: d.confidence_label,
    escalation_level: d.escalation_level,
    escalation_action: d.escalation_action,
    sla_hours: d.sla_hours,
    notifications_sent: d.notifications,
    summary: {
      mitre_techniques_count: (d.mitre_techniques || []).length,
      ioc_matches_count: (d.ioc_matches || []).length,
      yara_rules_count: d.yara_rules_count || 0,
      sec_filings_count: d.sec_filings_count || 0
    },
    group_profile: d.group_profile,
    mitre_techniques: d.mitre_techniques,
    ir_brief_markdown: d.ir_brief_markdown,
    generated_at: d.generated_at
  }
}];

// No valid artifacts — return error
return [{
  json: {
    status: 'error',
    error: 'Insufficient incident artifacts provided.',
    message: 'Please submit at least one of: hashes, IPs, ransom note text, or observed TTPs.',
    expected_format: {
      scenario_format: 'See demo/scenario.json for full incident format',
      alert_format: {
        alert_id: 'string',
        victim_company: 'string',
        victim_sector: 'string',
        hashes: ['sha256_hash_1', 'sha256_hash_2'],
        ips: ['1.2.3.4'],
        domains: ['evil.example.com'],
        ransom_note_text: 'YOUR FILES HAVE BEEN ENCRYPTED...',
        file_extension: '.locked',
        observed_ttps: ['RDP lateral movement', 'vssadmin shadow copy deletion']
      }
    }
  }
}];
